head.b:skin:
/* ══════════════════════════════════════
   TOOLSHUB PRO — BLOGGER THEME
   Full Design System
══════════════════════════════════════ */
:root{
  --bg:#0b0f1a;--bg2:#111827;--s1:#1a2234;--s2:#1e2a3e;--s3:#243147;--s4:#2c3d58;
  --br:#2e3f5c;--br2:#3a4f6e;--a:#3b82f6;--a2:#6366f1;--a3:#22d3ee;
  --g:#10b981;--r:#ef4444;--y:#f59e0b;
  --tx:#e8edf5;--t2:#94a3b8;--t3:#4a6080;--t4:#2d3d55;
  --grad:linear-gradient(135deg,#3b82f6 0%,#6366f1 50%,#22d3ee 100%);
  --card-shadow:0 4px 24px rgba(0,0,0,.4);--nav-h:64px;
  --font-display:'Syne',sans-serif;--font-body:'DM Sans',sans-serif;
  --radius:12px;--radius-lg:18px;--radius-xl:24px;
  --ease:cubic-bezier(.22,1,.36,1);
}
body.light-mode{
  --bg:#f0f4f8;--bg2:#ffffff;--s1:#ffffff;--s2:#f5f8fc;--s3:#edf2f7;--s4:#e2e8f0;
  --br:#d1dce9;--br2:#bac8d8;--a:#2563eb;--a2:#4f46e5;--a3:#0891b2;
  --tx:#0f1f36;--t2:#334e68;--t3:#627d98;--t4:#9fb3c8;
  --card-shadow:0 4px 20px rgba(0,0,0,.08);
}
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0;}
html{scroll-behavior:smooth;}
body{font-family:var(--font-body);background:var(--bg);color:var(--tx);font-size:15px;line-height:1.65;-webkit-font-smoothing:antialiased;overflow-x:hidden;}
a{color:var(--a);text-decoration:none;transition:color .2s;}
img{max-width:100%;height:auto;}
::-webkit-scrollbar{width:5px;}
::-webkit-scrollbar-track{background:var(--bg);}
::-webkit-scrollbar-thumb{background:var(--br2);border-radius:3px;}
.container{max-width:1200px;margin:0 auto;padding:0 20px;}

/* ── SCROLL PROGRESS ── */
#scroll-progress{position:fixed;top:0;left:0;height:3px;width:0%;z-index:9999;background:var(--grad);border-radius:0 3px 3px 0;pointer-events:none;}

/* ── HEADER ── */
#lp-header{
  position:sticky;top:0;z-index:1000;height:var(--nav-h);
  background:rgba(11,15,26,.92);backdrop-filter:blur(20px) saturate(180%);
  -webkit-backdrop-filter:blur(20px) saturate(180%);
  border-bottom:1px solid rgba(255,255,255,.06);
  transition:box-shadow .3s,background .3s;
  animation:headerLoad .6s cubic-bezier(.22,1,.36,1) both;
}
@keyframes headerLoad{from{opacity:0;transform:translateY(-100%)}to{opacity:1;transform:translateY(0)}}
body.light-mode #lp-header{background:rgba(255,255,255,.92);border-bottom-color:rgba(0,0,0,.07);}
#lp-header.scrolled{box-shadow:0 8px 40px rgba(0,0,0,.28);}
.header-inner{display:flex;align-items:center;height:var(--nav-h);gap:0;}
.lp-logo{display:flex;align-items:center;gap:10px;text-decoration:none;flex-shrink:0;}
.lp-logo-icon{width:38px;height:38px;border-radius:11px;background:linear-gradient(135deg,#1e40af,#312e81);border:1px solid rgba(99,102,241,.35);display:flex;align-items:center;justify-content:center;font-size:18px;box-shadow:0 2px 12px rgba(59,130,246,.3);}
.lp-logo-text{font-family:var(--font-display);font-size:19px;font-weight:800;letter-spacing:-.5px;background:var(--grad);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;}
.lp-nav{flex:1;display:flex;align-items:center;justify-content:center;gap:2px;}
.nav-item{position:relative;}
.nav-link{display:flex;align-items:center;gap:5px;padding:8px 14px;border-radius:9px;font-size:14px;font-weight:500;color:var(--t2);text-decoration:none;white-space:nowrap;transition:all .18s;}
.nav-link svg{transition:transform .2s;width:12px;height:12px;fill:none;stroke:currentColor;stroke-width:2.5;}
.nav-link:hover,.nav-item:hover>.nav-link{color:var(--a);background:var(--s3);}
.nav-item:hover>.nav-link svg{transform:rotate(180deg);}
.nav-dropdown{position:absolute;top:calc(100% + 10px);left:50%;transform:translateX(-50%) translateY(8px);background:var(--s1);border:1px solid var(--br2);border-radius:var(--radius-lg);padding:8px;min-width:220px;max-width:680px;box-shadow:0 24px 64px rgba(0,0,0,.5),0 4px 16px rgba(0,0,0,.2);opacity:0;visibility:hidden;pointer-events:none;transition:all .22s cubic-bezier(.4,0,.2,1);z-index:500;}
.nav-item:hover .nav-dropdown{opacity:1;visibility:visible;pointer-events:auto;transform:translateX(-50%) translateY(0);}
.nav-dropdown.g2{display:grid;grid-template-columns:1fr 1fr;gap:4px;min-width:420px;}
.nav-dropdown.g3{display:grid;grid-template-columns:1fr 1fr 1fr;gap:4px;min-width:580px;}
.dd-hd{grid-column:1/-1;padding:6px 12px 4px;font-size:10px;font-weight:800;letter-spacing:1.5px;text-transform:uppercase;color:var(--t3);display:flex;align-items:center;gap:6px;}
.dd-hd::after{content:'';flex:1;height:1px;background:var(--br);}
.dd-item{display:flex;align-items:center;gap:10px;padding:10px 12px;border-radius:10px;text-decoration:none;color:var(--t2);transition:all .15s;}
.dd-item:hover{background:var(--s3);color:var(--tx);}
.dd-ico{width:36px;height:36px;border-radius:10px;flex-shrink:0;display:flex;align-items:center;justify-content:center;font-size:17px;}
.dd-n{font-size:13px;font-weight:600;color:var(--tx);}
.dd-d{font-size:11px;color:var(--t3);margin-top:1px;}
.header-right{display:flex;align-items:center;gap:8px;flex-shrink:0;margin-left:auto;}
.h-search{display:flex;align-items:center;gap:7px;padding:7px 14px;border-radius:50px;background:var(--s3);border:1px solid var(--br);color:var(--t2);font-size:13px;cursor:pointer;transition:all .2s;font-family:var(--font-body);}
.h-search:hover{border-color:var(--a);color:var(--a);}
.theme-btn{width:36px;height:36px;border-radius:10px;background:var(--s3);border:1px solid var(--br);color:var(--t2);cursor:pointer;display:flex;align-items:center;justify-content:center;font-size:16px;transition:all .2s;}
.theme-btn:hover{border-color:var(--a);color:var(--a);}
.h-cta{background:var(--grad);color:#fff;padding:9px 20px;border-radius:50px;font-size:13px;font-weight:700;text-decoration:none;box-shadow:0 4px 14px rgba(59,130,246,.35);transition:all .2s;}
.h-cta:hover{transform:translateY(-1px);box-shadow:0 8px 24px rgba(59,130,246,.5);color:#fff;}
.mob-btn{display:none;width:36px;height:36px;border-radius:10px;background:var(--s3);border:1px solid var(--br);color:var(--t2);cursor:pointer;align-items:center;justify-content:center;flex-direction:column;gap:5px;}
.mob-btn span{display:block;width:18px;height:2px;background:currentColor;border-radius:2px;}

/* ── MOBILE NAV ── */
.mob-nav{display:none;position:fixed;inset:0;z-index:1500;background:rgba(0,0,0,.82);backdrop-filter:blur(12px);}
.mob-nav.open{display:flex;}
.mob-nav-inner{width:min(340px,90vw);height:100%;background:var(--s1);border-right:1px solid var(--br2);overflow-y:auto;padding:0 0 40px;animation:slideLeft .28s var(--ease);}
@keyframes slideLeft{from{transform:translateX(-100%)}to{transform:translateX(0)}}
.mob-head{display:flex;align-items:center;justify-content:space-between;padding:16px 18px;border-bottom:1px solid var(--br);}
.mob-close{width:32px;height:32px;border-radius:50%;background:var(--s3);border:1px solid var(--br);color:var(--t2);cursor:pointer;display:flex;align-items:center;justify-content:center;font-size:15px;}
.mob-list{padding:10px 0;}
.mob-sec{font-size:9px;font-weight:800;letter-spacing:1.6px;text-transform:uppercase;color:var(--t3);padding:12px 20px 5px;}
.mob-item{display:flex;align-items:center;gap:12px;padding:11px 20px;font-size:14px;color:var(--t2);text-decoration:none;transition:background .15s;}
.mob-item:hover{background:var(--s3);color:var(--tx);}
.mob-ico{width:34px;height:34px;border-radius:9px;flex-shrink:0;display:flex;align-items:center;justify-content:center;font-size:16px;}
.mob-div{height:1px;background:var(--br);margin:8px 0;}

/* ── SEARCH OVERLAY ── */
.search-ov{display:none;position:fixed;inset:0;z-index:2000;background:rgba(0,0,0,.82);backdrop-filter:blur(14px);align-items:flex-start;justify-content:center;padding-top:80px;}
.search-ov.open{display:flex;animation:fadeIn .2s ease;}
.search-box{width:min(640px,calc(100% - 40px));background:var(--s1);border:1px solid var(--br2);border-radius:var(--radius-xl);overflow:hidden;box-shadow:0 32px 80px rgba(0,0,0,.6);}
.s-row{display:flex;align-items:center;padding:0 20px;border-bottom:1px solid var(--br);}
.s-row .si{font-size:20px;flex-shrink:0;}
.s-inp{flex:1;padding:18px 14px;background:transparent;border:none;outline:none;font-size:17px;color:var(--tx);font-family:var(--font-body);}
.s-inp::placeholder{color:var(--t3);}
.s-close{width:32px;height:32px;border-radius:8px;background:var(--s3);border:1px solid var(--br);color:var(--t2);cursor:pointer;display:flex;align-items:center;justify-content:center;font-size:13px;}
.s-hints{padding:16px 20px;font-size:12px;color:var(--t3);display:flex;gap:10px;flex-wrap:wrap;align-items:center;}
.s-tag{padding:4px 11px;border-radius:50px;background:var(--s3);border:1px solid var(--br);color:var(--t2);cursor:pointer;font-size:12px;font-weight:500;transition:all .18s;}
.s-tag:hover{border-color:var(--a);color:var(--a);}

/* ── HERO (HOMEPAGE) ── */
.lp-hero{position:relative;overflow:hidden;padding:110px 0 100px;background:var(--bg2);}
.hero-bg{position:absolute;inset:0;pointer-events:none;background:radial-gradient(ellipse at 18% 28%,rgba(59,130,246,.18) 0,transparent 55%),radial-gradient(ellipse at 82% 72%,rgba(99,102,241,.15) 0,transparent 50%),radial-gradient(ellipse at 55% 8%,rgba(34,211,238,.1) 0,transparent 42%);}
body.light-mode .hero-bg{background:radial-gradient(ellipse at 18% 28%,rgba(37,99,235,.07) 0,transparent 55%),radial-gradient(ellipse at 82% 72%,rgba(79,70,229,.05) 0,transparent 50%);}
.hero-dots{position:absolute;inset:0;pointer-events:none;opacity:.25;background-image:radial-gradient(circle,var(--br2) 1px,transparent 1px);background-size:30px 30px;animation:dotMove 80s linear infinite;}
@keyframes dotMove{from{background-position:0 0}to{background-position:600px 600px}}
body.light-mode .hero-dots{opacity:.12;}
.orb{position:absolute;border-radius:50%;filter:blur(70px);pointer-events:none;}
.orb1{width:500px;height:500px;background:rgba(59,130,246,.1);top:-150px;left:-120px;animation:orb1 14s ease-in-out infinite;}
.orb2{width:380px;height:380px;background:rgba(99,102,241,.09);bottom:-100px;right:-80px;animation:orb2 11s ease-in-out infinite;}
.orb3{width:260px;height:260px;background:rgba(34,211,238,.07);top:35%;right:12%;animation:orb3 16s ease-in-out infinite;}
@keyframes orb1{0%,100%{transform:translate(0,0) scale(1)}50%{transform:translate(40px,-50px) scale(1.1)}}
@keyframes orb2{0%,100%{transform:translate(0,0) scale(1)}50%{transform:translate(-30px,40px) scale(1.08)}}
@keyframes orb3{0%,100%{transform:translate(0,0) scale(1)}50%{transform:translate(25px,-30px) scale(1.12)}}
.hero-inner{position:relative;z-index:2;text-align:center;}
.hero-badge{display:inline-flex;align-items:center;gap:8px;padding:7px 18px;border-radius:50px;background:rgba(59,130,246,.1);border:1px solid rgba(59,130,246,.25);font-size:12px;font-weight:700;color:#60a5fa;letter-spacing:.4px;margin-bottom:30px;animation:fadeUp .5s .1s both,glowPulse 3.5s ease-in-out 1.5s infinite;}
.badge-dot{width:6px;height:6px;border-radius:50%;background:#60a5fa;animation:blink 1.4s ease-in-out infinite;}
@keyframes blink{0%,100%{opacity:1;transform:scale(1)}50%{opacity:.2;transform:scale(.7)}}
.hero-title{font-family:var(--font-display);font-size:clamp(38px,7vw,72px);font-weight:800;letter-spacing:-2.5px;line-height:1.05;color:var(--tx);margin-bottom:24px;animation:fadeUp .7s .2s both;}
.grad-txt{background:var(--grad);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;}
.hero-sub{font-size:17px;color:var(--t2);max-width:600px;margin:0 auto 44px;line-height:1.8;animation:fadeUp .7s .3s both;}
.hero-search{max-width:660px;margin:0 auto 52px;animation:fadeUp .7s .4s both;}
.hs-outer{position:relative;}
.hs-glow{position:absolute;inset:-2px;border-radius:60px;background:var(--grad);opacity:0;transition:opacity .4s var(--ease);filter:blur(12px);z-index:0;pointer-events:none;}
.hs-outer.focused .hs-glow{opacity:.35;}
.hs-inner{position:relative;z-index:1;display:flex;align-items:center;background:var(--s1);border:1.5px solid var(--br2);border-radius:54px;padding:7px 7px 7px 22px;box-shadow:0 8px 40px rgba(0,0,0,.2);transition:border-color .35s,box-shadow .35s;}
.hs-outer.focused .hs-inner{border-color:rgba(99,130,246,.7);box-shadow:0 8px 40px rgba(0,0,0,.25),0 0 0 5px rgba(59,130,246,.12);}
.hs-icon-wrap{display:flex;align-items:center;justify-content:center;color:var(--t3);flex-shrink:0;margin-right:4px;transition:color .3s;}
.hs-outer.focused .hs-icon-wrap{color:var(--a);}
.hs-input{flex:1;background:transparent;border:none;outline:none;font-family:var(--font-body);font-size:15.5px;color:var(--tx);padding:11px 12px;min-width:0;caret-color:var(--a);}
.hs-input::placeholder{color:var(--t3);}
.hs-btn{display:flex;align-items:center;gap:8px;flex-shrink:0;padding:12px 26px;border-radius:50px;background:var(--grad);border:none;color:#fff;font-family:var(--font-body);font-size:14px;font-weight:700;cursor:pointer;box-shadow:0 4px 18px rgba(59,130,246,.38);transition:all .25s var(--ease);}
.hs-btn:hover{transform:scale(1.05);box-shadow:0 8px 28px rgba(59,130,246,.55);}
.hs-tags{display:flex;align-items:center;gap:8px;margin-top:14px;flex-wrap:wrap;justify-content:center;}
.hs-hint{font-size:12px;color:var(--t3);font-weight:500;}
.hs-tag{padding:5px 14px;border-radius:50px;background:rgba(255,255,255,.05);border:1px solid var(--br);color:var(--t2);font-size:12px;font-weight:600;font-family:var(--font-body);cursor:pointer;transition:all .2s;}
.hs-tag:hover{border-color:var(--a);color:var(--a);background:rgba(59,130,246,.08);}
body.light-mode .hs-tag{background:rgba(0,0,0,.04);}
.hero-stats{display:flex;align-items:center;justify-content:center;gap:40px;animation:fadeUp .7s .5s both;flex-wrap:wrap;}
.stat{text-align:center;}
.stat-val{font-family:var(--font-display);font-size:28px;font-weight:800;line-height:1;background:var(--grad);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;}
.stat-lbl{font-size:12px;color:var(--t3);margin-top:4px;letter-spacing:.3px;}
.stat-sep{width:1px;height:40px;background:var(--br);}

/* ── FEATURES ── */
.features{padding:96px 0;background:var(--bg2);border-top:1px solid var(--br);}
.sec-head{text-align:center;margin-bottom:60px;}
.sec-tag{display:inline-flex;align-items:center;gap:6px;padding:5px 16px;border-radius:50px;background:rgba(34,211,238,.1);border:1px solid rgba(34,211,238,.25);font-size:11px;font-weight:700;color:var(--a3);letter-spacing:.5px;text-transform:uppercase;margin-bottom:14px;}
.sec-title{font-family:var(--font-display);font-size:clamp(28px,4vw,44px);font-weight:800;letter-spacing:-1.2px;color:var(--tx);line-height:1.12;margin-bottom:14px;}
.sec-sub{font-size:16px;color:var(--t2);max-width:520px;margin:0 auto;line-height:1.75;}
.feat-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(240px,1fr));gap:22px;}
.feat-card{padding:34px 28px 30px;border-radius:var(--radius-lg);background:var(--s1);border:1px solid var(--br);position:relative;overflow:hidden;transition:transform .4s var(--ease),box-shadow .4s var(--ease),border-color .3s;}
.feat-card::before{content:'';position:absolute;bottom:0;left:0;right:0;height:3px;background:var(--grad);transform:scaleX(0);transform-origin:left;transition:transform .45s var(--ease);}
.feat-card:hover{transform:translateY(-10px);box-shadow:0 24px 56px rgba(0,0,0,.22),0 0 0 1px rgba(59,130,246,.12);border-color:rgba(59,130,246,.3);}
.feat-card:hover::before{transform:scaleX(1);}
.feat-ico-wrap{width:60px;height:60px;border-radius:18px;display:flex;align-items:center;justify-content:center;font-size:26px;margin-bottom:22px;background:linear-gradient(135deg,rgba(59,130,246,.18),rgba(99,102,241,.08));border:1px solid rgba(59,130,246,.25);}
.feat-title{font-family:var(--font-display);font-size:18px;font-weight:700;color:var(--tx);margin-bottom:10px;letter-spacing:-.3px;}
.feat-desc{font-size:14px;color:var(--t2);line-height:1.78;}

/* ── HOMEPAGE BLOG PREVIEW ── */
.blog-preview{padding:96px 0;background:var(--bg);border-top:1px solid var(--br);}
.blog-preview-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(300px,1fr));gap:24px;}
.bp-card{border-radius:var(--radius-lg);background:var(--s1);border:1px solid var(--br);overflow:hidden;display:flex;flex-direction:column;transition:transform .4s var(--ease),box-shadow .4s var(--ease),border-color .3s;text-decoration:none;color:inherit;}
.bp-card:hover{transform:translateY(-8px);box-shadow:0 24px 56px rgba(0,0,0,.22),0 0 0 1px rgba(59,130,246,.15);border-color:rgba(59,130,246,.3);}
.bp-thumb{width:100%;height:180px;background:linear-gradient(135deg,var(--s3),var(--s4));display:flex;align-items:center;justify-content:center;position:relative;overflow:hidden;}
.bp-thumb img{width:100%;height:100%;object-fit:cover;display:block;}
.bp-thumb-fallback{font-size:44px;position:relative;z-index:1;}
.bp-body{padding:20px 22px 18px;flex:1;display:flex;flex-direction:column;}
.bp-meta{display:flex;align-items:center;gap:10px;margin-bottom:10px;flex-wrap:wrap;}
.bp-cat{padding:3px 11px;border-radius:50px;font-size:10px;font-weight:800;letter-spacing:.8px;text-transform:uppercase;background:rgba(59,130,246,.1);border:1px solid rgba(59,130,246,.2);color:#60a5fa;}
.bp-date{font-size:12px;color:var(--t3);}
.bp-title{font-family:var(--font-display);font-size:16px;font-weight:700;color:var(--tx);line-height:1.35;margin-bottom:9px;letter-spacing:-.2px;}
.bp-excerpt{font-size:13px;color:var(--t2);line-height:1.75;flex:1;margin-bottom:14px;}
.bp-foot{display:flex;align-items:center;justify-content:space-between;border-top:1px solid var(--br);padding-top:12px;}
.bp-author{display:flex;align-items:center;gap:8px;}
.bp-av{width:26px;height:26px;border-radius:50%;background:var(--grad);display:flex;align-items:center;justify-content:center;font-size:12px;flex-shrink:0;}
.bp-author-name{font-size:12px;font-weight:600;color:var(--t2);}
.bp-read{font-size:12px;color:var(--a);font-weight:600;}
.blog-preview-more{text-align:center;margin-top:44px;}
.bp-more-btn{display:inline-flex;align-items:center;gap:8px;padding:13px 32px;border-radius:50px;border:1.5px solid var(--br2);background:var(--s1);color:var(--t2);font-size:14px;font-weight:600;text-decoration:none;transition:all .25s;}
.bp-more-btn:hover{border-color:var(--a);color:var(--a);background:rgba(59,130,246,.06);}

/* ── CTA ── */
.cta-sec{padding:96px 0;background:var(--bg2);border-top:1px solid var(--br);}
.cta-card{border-radius:var(--radius-xl);background:linear-gradient(135deg,#0f2460 0%,#1e1b6b 45%,#0e1a38 100%);border:1px solid rgba(255,255,255,.08);padding:80px 40px;text-align:center;position:relative;overflow:hidden;transition:transform .45s var(--ease),box-shadow .45s var(--ease);}
.cta-card:hover{transform:translateY(-5px);box-shadow:0 28px 64px rgba(0,0,0,.35);}
.cta-card::before{content:'';position:absolute;inset:0;background:radial-gradient(ellipse at 25% 55%,rgba(99,102,241,.28),transparent 58%),radial-gradient(ellipse at 75% 45%,rgba(34,211,238,.14),transparent 58%);}
.cta-inner{position:relative;z-index:1;}
.cta-badge{display:inline-flex;align-items:center;gap:6px;padding:5px 14px;border-radius:50px;background:rgba(255,255,255,.1);border:1px solid rgba(255,255,255,.15);font-size:11px;font-weight:700;color:rgba(255,255,255,.7);letter-spacing:.4px;text-transform:uppercase;margin-bottom:20px;}
.cta-title{font-family:var(--font-display);font-size:clamp(28px,4.5vw,48px);font-weight:800;color:#fff;letter-spacing:-1.5px;margin-bottom:16px;line-height:1.1;}
.cta-sub{font-size:16px;color:rgba(255,255,255,.6);max-width:500px;margin:0 auto 36px;line-height:1.7;}
.cta-btns{display:flex;gap:14px;justify-content:center;flex-wrap:wrap;}
.cta-btn1{padding:15px 32px;border-radius:50px;background:linear-gradient(135deg,#60a5fa,#818cf8);color:#fff;font-weight:700;font-size:15px;text-decoration:none;box-shadow:0 6px 24px rgba(96,165,250,.45);transition:all .25s;display:inline-flex;align-items:center;gap:8px;}
.cta-btn1:hover{transform:translateY(-3px);box-shadow:0 14px 36px rgba(96,165,250,.55);color:#fff;}
.cta-btn2{padding:15px 26px;border-radius:50px;background:rgba(255,255,255,.1);border:1.5px solid rgba(255,255,255,.22);color:rgba(255,255,255,.82);font-weight:600;font-size:15px;text-decoration:none;transition:all .25s;display:inline-flex;align-items:center;gap:8px;}
.cta-btn2:hover{background:rgba(255,255,255,.18);color:#fff;}

/* ── BLOG LISTING (non-homepage) ── */
.blog-hero-sec{padding:72px 0 56px;background:var(--bg2);border-bottom:1px solid var(--br);position:relative;overflow:hidden;}
.blog-hero-bg{position:absolute;inset:0;pointer-events:none;background:radial-gradient(ellipse at 20% 40%,rgba(59,130,246,.14) 0,transparent 55%),radial-gradient(ellipse at 80% 60%,rgba(99,102,241,.10) 0,transparent 50%);}
.blog-hero-inner{position:relative;z-index:1;animation:fadeUp .6s .1s both;}
.breadcrumb{display:flex;align-items:center;gap:6px;font-size:13px;color:var(--t3);margin-bottom:20px;}
.breadcrumb a{color:var(--t3);}
.breadcrumb a:hover{color:var(--a);}
.breadcrumb span{color:var(--t4);}
.blog-hero-tag{display:inline-flex;align-items:center;gap:6px;padding:5px 16px;border-radius:50px;background:rgba(34,211,238,.1);border:1px solid rgba(34,211,238,.25);font-size:11px;font-weight:700;color:var(--a3);letter-spacing:.5px;text-transform:uppercase;margin-bottom:16px;}
.blog-hero-title{font-family:var(--font-display);font-size:clamp(32px,5vw,52px);font-weight:800;letter-spacing:-1.5px;color:var(--tx);line-height:1.1;margin-bottom:14px;}
.blog-hero-sub{font-size:16px;color:var(--t2);max-width:520px;line-height:1.8;}
.blog-main-sec{padding:72px 0 96px;}
.blog-layout{display:grid;grid-template-columns:1fr 300px;gap:36px;align-items:start;}
.posts-list{display:flex;flex-direction:column;gap:24px;}

/* ── POST CARDS (blog listing) ── */
.post-card{background:var(--s1);border:1px solid var(--br);border-radius:var(--radius-lg);overflow:hidden;transition:transform .4s var(--ease),box-shadow .4s,border-color .3s;}
.post-card:hover{transform:translateY(-6px);box-shadow:0 20px 48px rgba(0,0,0,.22),0 0 0 1px rgba(59,130,246,.12);border-color:rgba(59,130,246,.25);}
.post-card-img{width:100%;height:200px;background:linear-gradient(135deg,var(--s3),var(--s4));display:flex;align-items:center;justify-content:center;overflow:hidden;}
.post-card-img img{width:100%;height:200px;object-fit:cover;display:block;}
.post-card-body{padding:22px 22px 20px;}
.post-card-tags{display:flex;gap:7px;margin-bottom:12px;flex-wrap:wrap;}
.post-card-tag{padding:3px 11px;border-radius:50px;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;background:rgba(59,130,246,.1);border:1px solid rgba(59,130,246,.2);color:#60a5fa;text-decoration:none;}
.post-card-tag:hover{background:rgba(59,130,246,.18);}
.post-card-title{font-family:var(--font-display);font-size:19px;font-weight:700;color:var(--tx);letter-spacing:-.3px;line-height:1.3;margin-bottom:10px;}
.post-card-title a{color:var(--tx);}
.post-card-title a:hover{color:var(--a);}
.post-card-excerpt{font-size:14px;color:var(--t2);line-height:1.7;margin-bottom:16px;}
.post-card-meta{display:flex;align-items:center;gap:14px;font-size:12px;color:var(--t3);padding-top:14px;border-top:1px solid var(--br);flex-wrap:wrap;}
.post-meta-item{display:flex;align-items:center;gap:5px;}
.post-read-more{margin-left:auto;font-size:13px;font-weight:600;color:var(--a);text-decoration:none;display:flex;align-items:center;gap:4px;}
.post-read-more:hover{gap:7px;}

/* ── SINGLE POST ── */
.post-single{max-width:760px;}
.post-single-header{margin-bottom:32px;}
.post-single-title{font-family:var(--font-display);font-size:clamp(26px,4vw,40px);font-weight:800;letter-spacing:-1px;color:var(--tx);line-height:1.15;margin-bottom:16px;}
.post-single-meta{display:flex;align-items:center;gap:16px;font-size:13px;color:var(--t3);flex-wrap:wrap;padding-bottom:20px;border-bottom:1px solid var(--br);}
.post-single-img{width:100%;border-radius:var(--radius-lg);overflow:hidden;margin:24px 0;border:1px solid var(--br);}
.post-single-img img{width:100%;display:block;}
.post-content{font-size:16px;line-height:1.85;color:var(--t2);}
.post-content h1,.post-content h2,.post-content h3,.post-content h4{font-family:var(--font-display);color:var(--tx);margin:32px 0 14px;font-weight:700;letter-spacing:-.3px;line-height:1.2;}
.post-content h2{font-size:26px;}.post-content h3{font-size:21px;}
.post-content p{margin-bottom:18px;}
.post-content a{color:var(--a);border-bottom:1px solid rgba(59,130,246,.3);}
.post-content a:hover{border-bottom-color:var(--a);}
.post-content ul,.post-content ol{margin:0 0 18px 22px;}
.post-content li{margin-bottom:7px;}
.post-content blockquote{margin:24px 0;padding:18px 22px;border-left:4px solid var(--a);background:rgba(59,130,246,.06);border-radius:0 var(--radius) var(--radius) 0;font-style:italic;color:var(--t2);}
.post-content code{background:var(--s3);padding:2px 7px;border-radius:5px;font-size:13px;color:var(--a3);}
.post-content pre{background:var(--s2);border:1px solid var(--br);border-radius:var(--radius);padding:18px;overflow-x:auto;margin:24px 0;}
.post-content pre code{background:none;padding:0;}
.post-content img{max-width:100%;border-radius:var(--radius);margin:18px 0;}
.post-content table{width:100%;border-collapse:collapse;margin:24px 0;font-size:14px;}
.post-content th,.post-content td{padding:12px 16px;border:1px solid var(--br);text-align:left;}
.post-content th{background:var(--s3);font-weight:700;color:var(--tx);}
.post-tags{margin-top:36px;padding-top:20px;border-top:1px solid var(--br);}

/* ── SIDEBAR ── */
.sidebar{position:sticky;top:calc(var(--nav-h) + 20px);}
.sw{background:var(--s1);border:1px solid var(--br);border-radius:var(--radius-lg);overflow:hidden;margin-bottom:20px;}
.sw-head{padding:14px 18px;border-bottom:1px solid var(--br);font-family:var(--font-display);font-size:14px;font-weight:700;color:var(--tx);display:flex;align-items:center;gap:8px;}
.sw-head::before{content:'';width:3px;height:14px;background:var(--a);border-radius:2px;}
.sw-body{padding:14px 18px;}
.sw-tool-list{display:flex;flex-direction:column;gap:4px;}
.sw-tool-item{display:flex;align-items:center;gap:10px;padding:9px 12px;border-radius:10px;cursor:pointer;transition:background .15s;text-decoration:none;color:var(--t2);}
.sw-tool-item:hover{background:var(--s3);color:var(--tx);}
.sw-ico{width:32px;height:32px;border-radius:9px;display:flex;align-items:center;justify-content:center;font-size:16px;flex-shrink:0;}
.sw-tool-name{font-size:13px;font-weight:600;}
.labels-cloud{display:flex;flex-wrap:wrap;gap:7px;}
.label-link{display:inline-flex;align-items:center;padding:5px 13px;border-radius:50px;font-size:12px;font-weight:600;color:var(--t2);background:var(--s3);border:1px solid var(--br);text-decoration:none;transition:all .2s;}
.label-link:hover{border-color:var(--a);color:var(--a);background:rgba(59,130,246,.08);}
.sw-cta-btn{display:flex;align-items:center;justify-content:center;gap:7px;padding:11px 22px;width:100%;margin-top:14px;border-radius:50px;background:var(--grad);color:#fff;font-size:13px;font-weight:700;text-decoration:none;box-shadow:0 4px 16px rgba(59,130,246,.35);transition:all .2s;}
.sw-cta-btn:hover{transform:translateY(-1px);box-shadow:0 8px 24px rgba(59,130,246,.5);color:#fff;}

/* ── PAGINATION ── */
.pagination{display:flex;align-items:center;justify-content:center;gap:6px;padding:48px 0 0;flex-wrap:wrap;}
.page-link{width:40px;height:40px;border-radius:10px;display:flex;align-items:center;justify-content:center;font-size:14px;font-weight:600;text-decoration:none;transition:all .2s;background:var(--s1);border:1px solid var(--br);color:var(--t2);}
.page-link:hover{border-color:var(--a);color:var(--a);background:var(--s3);}
.page-prev,.page-next{padding:0 16px;width:auto;gap:6px;}

/* ── FOOTER ── */
#lp-footer{background:var(--bg2);border-top:1px solid var(--br);padding:72px 0 0;}
.footer-grid{display:grid;grid-template-columns:280px repeat(3,1fr);gap:48px;margin-bottom:56px;}
.footer-logo-wrap{display:flex;align-items:center;gap:10px;margin-bottom:14px;}
.footer-logo-ico{width:36px;height:36px;border-radius:10px;background:linear-gradient(135deg,#1e40af,#312e81);border:1px solid rgba(99,102,241,.35);display:flex;align-items:center;justify-content:center;font-size:17px;}
.footer-logo-txt{font-family:var(--font-display);font-size:18px;font-weight:800;background:var(--grad);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;}
.footer-desc{font-size:13px;color:var(--t3);line-height:1.8;margin-bottom:22px;}
.footer-social{display:flex;gap:8px;}
.s-btn{width:36px;height:36px;border-radius:9px;background:var(--s3);border:1px solid var(--br);display:flex;align-items:center;justify-content:center;font-size:15px;text-decoration:none;color:var(--t2);transition:all .2s;}
.s-btn:hover{border-color:var(--a);color:var(--a);background:rgba(59,130,246,.08);}
.footer-col-title{font-size:11px;font-weight:800;letter-spacing:1.6px;text-transform:uppercase;color:var(--t2);margin-bottom:18px;}
.footer-links{display:flex;flex-direction:column;gap:10px;}
.footer-link{font-size:13px;color:var(--t3);text-decoration:none;transition:all .2s;}
.footer-link:hover{color:var(--tx);padding-left:4px;}
.footer-bottom{border-top:1px solid var(--br);padding:22px 0;display:flex;align-items:center;justify-content:space-between;font-size:12px;color:var(--t3);flex-wrap:wrap;gap:12px;}
.footer-bottom-links{display:flex;gap:20px;}
.footer-bottom-links a{color:var(--t3);text-decoration:none;transition:color .2s;}
.footer-bottom-links a:hover{color:var(--tx);}

/* ── ANIMATIONS ── */
@keyframes fadeUp{from{opacity:0;transform:translateY(24px)}to{opacity:1;transform:translateY(0)}}
@keyframes fadeIn{from{opacity:0}to{opacity:1}}
@keyframes floatSoft{0%,100%{transform:translateY(0)}50%{transform:translateY(-6px)}}
@keyframes glowPulse{0%,100%{box-shadow:0 0 0 0 rgba(59,130,246,0)}50%{box-shadow:0 0 0 14px rgba(59,130,246,.06)}}
.reveal{opacity:0;transform:translateY(28px) scale(.98);transition:opacity .7s cubic-bezier(.22,1,.36,1),transform .7s cubic-bezier(.22,1,.36,1);transition-delay:0s;}
.reveal.visible{opacity:1;transform:translateY(0) scale(1);}
.reveal.visible.d1{transition-delay:.06s}.reveal.visible.d2{transition-delay:.13s}.reveal.visible.d3{transition-delay:.20s}.reveal.visible.d4{transition-delay:.27s}

/* ── RESPONSIVE ── */
@media(max-width:1024px){.footer-grid{grid-template-columns:1fr 1fr;}.blog-layout{grid-template-columns:1fr;}.sidebar{position:static;}}
@media(max-width:768px){.lp-nav{display:none;}.mob-btn{display:flex;}.h-search{display:none;}.hero-stats{gap:22px;}.stat-sep{display:none;}.cta-card{padding:56px 24px;}.footer-grid{grid-template-columns:1fr 1fr;}}
@media(max-width:480px){.footer-grid{grid-template-columns:1fr;}.hs-inner{flex-direction:column;border-radius:20px;padding:14px;gap:10px;}.hs-btn{width:100%;justify-content:center;}.cta-btns{flex-direction:column;align-items:center;}.blog-preview-grid{grid-template-columns:1fr;}}
@media(prefers-reduced-motion:reduce){*,*::before,*::after{animation:none !important;transition:none !important;}.reveal{opacity:1;transform:none;}}

body.script:
//
/* ── Theme ── */
(function(){
  var s=localStorage.getItem('th')||'dark';
  if(s==='light')document.body.classList.add('light-mode');
  var b=document.getElementById('theme-btn');
  if(b)b.textContent=s==='light'?'\u{1F319}':'\u2600\uFE0F';
})();
function toggleTheme(){
  var l=document.body.classList.toggle('light-mode');
  localStorage.setItem('th',l?'light':'dark');
  var b=document.getElementById('theme-btn');
  if(b)b.textContent=l?'\u{1F319}':'\u2600\uFE0F';
}

/* ── Mobile nav ── */
function openMob(){document.getElementById('mob-nav').classList.add('open');document.body.style.overflow='hidden';}
function closeMob(){document.getElementById('mob-nav').classList.remove('open');document.body.style.overflow='';}

/* ── Search overlay ── */
function openSearch(){
  document.getElementById('search-ov').classList.add('open');
  setTimeout(function(){var i=document.getElementById('s-inp');if(i)i.focus();},150);
}
function closeSearch(){document.getElementById('search-ov').classList.remove('open');}
function doSearch(){
  var v=document.getElementById('s-inp').value.trim();
  if(v)window.location.href='/search?q='+encodeURIComponent(v);
}
function searchFor(t){
  var i=document.getElementById('s-inp');
  if(i){i.value=t;}
  openSearch();
}

/* ── Hero search ── */
function setSearch(q){
  var el=document.getElementById('hero-inp');
  if(el){el.value=q;el.focus();}
}
function heroSearch(){
  var el=document.getElementById('hero-inp');
  var v=el?el.value.trim():'';
  if(v)window.location.href='/search?q='+encodeURIComponent(v);
}

/* ── Hero search focus glow ── */
(function(){
  var el=document.getElementById('hero-inp');
  var outer=document.getElementById('hs-outer');
  if(!el||!outer)return;
  el.addEventListener('focus',function(){outer.classList.add('focused');});
  el.addEventListener('blur',function(){outer.classList.remove('focused');});

  /* Typewriter placeholder */
  var phrases=['Search from 100+ free tools...','Try "PDF Merger"...','Try "Image Converter"...','Try "Password Generator"...','Try "Translator"...','Try "Calculator"...'];
  var pi=0,ci=0,del=false;
  function type(){
    if(document.activeElement===el)return;
    var ph=phrases[pi];
    if(!del){
      if(ci<=ph.length){el.placeholder=ph.slice(0,ci);ci++;setTimeout(type,55);}
      else{setTimeout(function(){del=true;type();},2000);}
    } else {
      if(ci>0){el.placeholder=ph.slice(0,ci);ci--;setTimeout(type,30);}
      else{del=false;pi=(pi+1)%phrases.length;setTimeout(type,400);}
    }
  }
  type();
  el.addEventListener('blur',function(){setTimeout(type,600);});
})();

/* ── Keyboard ── */
document.addEventListener('keydown',function(e){
  if(e.key==='Escape'){closeSearch();closeMob();}
  if((e.ctrlKey||e.metaKey)&&e.key==='k'){e.preventDefault();openSearch();}
});

/* ── Header scroll ── */
window.addEventListener('scroll',function(){
  document.getElementById('lp-header').classList.toggle('scrolled',window.scrollY>20);
},{passive:true});

/* ── Footer year ── */
var yr=document.getElementById('yr');
if(yr)yr.textContent=new Date().getFullYear();

/* ── Scroll progress bar ── */
(function(){
  var bar=document.getElementById('scroll-progress');
  if(!bar)return;
  function upd(){
    var sc=window.scrollY,tot=document.body.scrollHeight-window.innerHeight;
    bar.style.width=(tot>0?(sc/tot*100):0)+'%';
  }
  window.addEventListener('scroll',upd,{passive:true});
  upd();
})();

/* ── Scroll reveal ── */
(function(){
  if(!('IntersectionObserver' in window)){
    document.querySelectorAll('.reveal').forEach(function(el){el.classList.add('visible');});
    return;
  }
  var observer=new IntersectionObserver(function(entries){
    entries.forEach(function(entry){
      if(entry.isIntersecting)entry.target.classList.add('visible');
      else entry.target.classList.remove('visible');
    });
  },{threshold:0.07,rootMargin:'0px 0px -30px 0px'});
  document.querySelectorAll('.reveal').forEach(function(el){observer.observe(el);});
})();
//
